CREATE TABLE `subscriptions` (
  `AccountID` varchar(7) NOT NULL,
  `RepeatCustomer` varchar(3) DEFAULT NULL,
  `Promotion` varchar(3) DEFAULT NULL,
  `PlanType` varchar(11) DEFAULT NULL,
  `BaseFee` float(5,3) DEFAULT NULL,
  `AdditionalFeatureSpend` int DEFAULT NULL,
  `NumberOfPenalties` int DEFAULT NULL,
  `StartDate` varchar(8) DEFAULT NULL,
  `CancelDate` varchar(8) DEFAULT NULL,
  `StartMonth` varchar(3) DEFAULT NULL,
  `StartWeek` varchar(3) DEFAULT NULL,
  `CustomerTenure` int DEFAULT NULL,
  PRIMARY KEY (`AccountID`),
  UNIQUE KEY `idx_subscriptions_AccountID` (`AccountID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
